<template>
    <view class="container">
        <view class="item">
            <view class="item_title">
                ご利用プラン
            </view>
            <view class="item_detail">
                <view class="detail_item">
                    <view class="detail_item_left">
                        ご利用中のプラン：
                    </view>
                    <view class="detail_item_right">
                        {{using.type == 1? 'ライト' : using.type == 2? 'スタンダード' : 'プレミアム'}}
                    </view>
                </view>
                <view class="detail_item">
                    <view class="detail_item_left">
                        オプション：
                    </view>
                    <view class="detail_item_right">
                        クーポン機能
                    </view>
                </view>
                <view class="checkMore">
                    プランを変更
                </view>
            </view>
        </view>

        <view class="item">
            <view class="item_title">
                お支払い周期を選択してください
            </view>
            <view class="item_list">
                <view class="list_item">
                    <view class="selectContent" @click="chooseTime(12)">
                        <view class="selectInner" v-if="current == 12"></view>
                    </view>
                    <view class="selectTime">
                        1年
                    </view>
                    <view class="selectPrice">
                        ¥{{price3 / 12}} × 12ヶ月
                    </view>
                    <view class="selectDisccount">
                        ¥{{price1 * 12 - price3}} お得！
                    </view>
                </view>

                <view class="list_item">
                    <view class="selectContent" @click="chooseTime(6)">
                        <view class="selectInner"  v-if="current == 6"></view>
                    </view>
                    <view class="selectTime">
                        6ヶ月
                    </view>
                    <view class="selectPrice">
                        ¥{{price2 / 6}} × 6ヶ月
                    </view>
                    <view class="selectDisccount">
                        ¥{{price1 * 6 - price2}} お得！
                    </view>
                </view>

                <view class="list_item">
                    <view class="selectContent" @click="chooseTime(1)">
                        <view class="selectInner"  v-if="current == 1"></view>
                    </view>
                    <view class="selectTime">
                        1ヶ月
                    </view>
                    <view class="selectPrice">
                        ¥{{price1}}
                    </view>
                    <view class="selectDisccount"></view>
                </view>
            </view>
        </view>
        <view class="item">
            <view class="item_title">
                お支払い方法を選択
            </view>
            <view class="paymethod">
                <view class="payItem">
                    <view class="pTop">
                        <view class="selectContent"  @click="changeMethods(1)">
                            <view class="selectInner" v-if="paymethod == 1"></view>
                        </view>
                        <view class="payName">
                            クレジットカード
                        </view>
                    </view>
                    <view class="cards">
                        <image src="../../static/images/ITF.png"></image>
                    </view>
                    <view class="cardsInfo">
                        <view class="payName">
                            カード情報を入力して下さい
                        </view>
                        <view class="info_item">
                            <view class="info_name">
                                カード番号
                            </view>
                            <view>
                                <u-input border="bottom" v-model="inp1"></u-input>
                            </view>
                        </view>
                        <view style="display: flex; align-items: center;justify-content: space-between;">
                            <view class="info_item">
                                <view class="info_name">
                                    有効期限
                                </view>
                                <view>
                                    <u-input placeholder="01/25" border="bottom" v-model="inp2"></u-input>
                                </view>
                            </view>
                            <view style="width: 42upx;"></view>
                            <view class="info_item">
                                <view class="info_name">
                                    CVV
                                </view>
                                <view>
                                    <u-input placeholder="3桁or4桁の数字" border="bottom" v-model="inp3"></u-input>
                                </view>
                            </view>
                        </view>
                        <view class="info_item">
                            <view class="info_name">
                                カード名義人
                            </view>
                            <view>
                                <u-input border="bottom" v-model="inp4"></u-input>
                            </view>
                        </view>
                    </view>
                </view>
                <view class="payItem">
                    <view class="pTop">
                        <view class="selectContent"  @click="changeMethods(2)">
                            <view class="selectInner"  v-if="paymethod == 2"></view>
                        </view>
                        <view class="applePay">
                            <image src="../../static/images/Apple pay.png" mode=""></image>
                        </view>
                        <view class="payName">
                            Apple Pay
                        </view>
                    </view>
                </view>
                <view class="payItem">
                    <view class="pTop">
                        <view class="selectContent" @click="changeMethods(3)">
                            <view class="selectInner"  v-if="paymethod == 3"></view>
                        </view>
                        <view class="googlePay">
                            <image src="../../static/images/google pay.png" mode=""></image>
                        </view>
                        <view class="payName">
                            Google Pay
                        </view>
                    </view>
                </view>
            </view>
        </view>
        
        <view class="item pd">
            <view class="detaTitle">
                内容
            </view>
            <view class="deta">
                <view class="detaItem">
                    スタンダードプラン
                </view>
                <view class="detaItem" v-if="current == 1">
                    ¥{{price1}} × 1ヶ月
                </view>
                <view class="detaItem" v-if="current == 6">
                    ¥{{price2 / 6}} × 6ヶ月
                </view>
                <view class="detaItem" v-if="current == 12">
                    ¥{{price3 / 12}} × 12ヶ月
                </view>
            </view>
            
            <view class="deta">
                <view class="detaItem">
                    合計
                </view>
                <view class="detaItem" v-if="current == 1">
                    ¥{{price1}}
                </view>
                <view class="detaItem" v-if="current == 6">
                    ¥{{price2}}
                </view>
                <view class="detaItem" v-if="current == 12">
                    ¥{{price3}}
                </view>
            </view>
        </view>
        
        <view class="tips">
            ご契約月は利用料が <text style="color: #D93025;">無料</text> です。　上記は次月からのご請求となります。
        </view>
        
        <u-button shape="circle" text="お申し込み手続き完了" type="primary" @click="toSuccess" ></u-button>
        <view style="height: 160upx;"></view>
    </view>
</template>

<script>
    import {getShopInfo,getPackageList,getCardInfo,buyPlan } from "@/api/index.js"
    export default {
        data() {
            return {
                type:0,
                price1:"",
                price2:"",
                price3:"",
                selectItem:{},
                current:12,
                paymethod:1,
                inp1:"",
                inp2:"",
                inp3:"",
                inp4:"",
                using:{}
            }
        },
        onLoad(options) {
            let that = this
            that.type = options.type
            that.getPlanList(options.type)
            that.getShopInfo()
            that.getCardInfo()
        },
        methods: {
            changeMethods(e){
              let that = this
              that.paymethod = e
            },
            toSuccess(){
                let that = this
                let data = {}
                data['type'] = that.type
                data['month'] = that.current
                data['card_type'] = that.paymethod
                data['card_no'] = that.inp1
                data['expire_date'] = that.inp2
                data['cvv'] = that.inp3
                data['name'] = that.inp4
                buyPlan(data).then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        if(res.data.amount > 0){
                           uni.navigateTo({
                               url:"../webview/webview?link="+res.data.url
                           })
                        }else{
                          uni.navigateTo({
                              url:"../paySuccess/paySuccess"
                          })
                        }
                        
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                })
               
            },
            chooseTime(e){
              this.current = e  
            },
            getCardInfo(){
              let that = this
              getCardInfo().then((res) => {
                  if(res.code == 200){
                      console.log("res",res)
                      if(res.data.cards.length > 0){
                          that.inp1 = res.data.cards[0].card_no
                          that.inp2 = res.data.cards[0].expire_date
                          that.inp3 = res.data.cards[0].cvv
                          that.inp4 = res.data.cards[0].name
                      }
                  }
              })
            },
            getPlanList(type){
                let that = this
                getPackageList().then((res) => {
                    console.log("packagelist",res)
                    if(res.code == 200){
                        that.selectItem = res.data.vip_contract[type - 1]
                        that.price1 = res.data.vip_contract[type - 1].price[0]
                        that.price2 = res.data.vip_contract[type - 1].price[1]
                        that.price3 = res.data.vip_contract[type - 1].price[2]
                        console.log(that.selectItem)
                    }
                })
            },
            getShopInfo(){
                let that = this
                getShopInfo().then((res) => {
                    console.log("shopList",res)
                    that.using = res.data.shop_info.vip
                })
            }
        }
    }
</script>

<style lang="scss">
    .detaTitle{
        font-size: 28upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #1D1D1F;
        padding-bottom: 20upx;
    }
    
    .tips{
        box-sizing: border-box;
        padding: 0 58upx;
        margin: 80upx auto;
        font-size: 28upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #0A4B6D;
    }
    
    .pd{
        box-sizing: border-box;
        padding: 48upx;
    }
    
    .deta{
        display: flex;
        justify-content: space-between;
        padding: 28upx 0;
        border-top: 2upx solid #D2D2D7;
        
        .deta_item{
            display: flex;
            align-items: center;
            justify-content: space-between;
            box-sizing: border-box;
            padding-left: 36upx;
            margin-top: 20upx;
        }
        
        .detaItem{
            font-size: 28upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
        }
    }
    
    .applePay {
        width: 94upx;
        height: 60upx;

        image {
            width: 100%;
            height: 100%;
        }
    }

    .googlePay {
        width: 124upx;
        height: 60upx;

        image {
            width: 100%;
            height: 100%;
        }
    }

    .selectContent {
        width: 32upx;
        height: 32upx;
        box-sizing: border-box;
        padding: 6upx;
        border: 2upx solid #1A73E8;
        border-radius: 50%;
        margin-right: 10upx;

        .selectInner {
            width: 100%;
            height: 100%;
            background: #1A73E8;
            border-radius: 50%;
        }
    }

    .paymethod {
        .payItem {
            box-sizing: border-box;
            padding: 48upx;
            border-bottom: 2upx solid #D2D2D7;

            .cardsInfo {
                margin-top: 80upx;

                .info_item {
                    margin-top: 60upx;
                    flex: 1;

                    .info_name {
                        font-size: 24upx;
                        font-family: Hiragino Sans-W5, Hiragino Sans;
                        font-weight: normal;
                        color: #707070;
                    }
                }
            }

            .pTop {
                display: flex;
                align-items: center;

                .payName {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W5, Hiragino Sans;
                    font-weight: normal;
                    color: #1D1D1F;
                }
            }

            .cards {
                width: 413upx;
                height: 60upx;
                margin-top: 20upx;

                image {
                    width: 100%;
                    height: 100%;
                }
            }
        }
    }

    .container {
        background-color: #fff;
        box-sizing: border-box;
        padding: 0 32upx;
    }

    .checkMore {
        font-size: 28upx;
        font-family: Hiragino Sans-W5, Hiragino Sans;
        font-weight: normal;
        color: #1A73E8;
        text-align: right;
    }

    .list_item {
        display: flex;
        box-sizing: border-box;
        padding: 40upx 32upx;
        border-bottom: 2upx solid #D2D2D7;
        align-items: center;

        .selectTime {
            width: 15%;
        }

        .selectPrice {
            width: 45%;
        }

        .selectDisccount {
            flex: 1;
            color: #D93025 !important;
        }
    }

    .item {
        box-shadow: 0px 0px 20upx 2upx rgba(0, 0, 0, 0.07);
        margin-top: 60upx;

        .item_title {
            box-sizing: border-box;
            padding: 24upx 46upx;
            background: rgba(26, 115, 232, 0.1);
            font-size: 28upx;
            font-family: Hiragino Sans-W5, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
        }

        .item_detail {
            box-sizing: border-box;
            padding: 40upx;

            .detail_item {
                display: flex;
                align-items: center;
                margin-bottom: 40upx;

                .detail_item_left {
                    font-size: 28upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #1D1D1F;
                }

                .detail_item_right {
                    font-size: 28upx;
                    font-family: Hiragino Sans-W5, Hiragino Sans;
                    font-weight: normal;
                    color: #1D1D1F;
                }

            }
        }
    }
</style>
